247	  padding: "8px 12px",
248	};
249

1	import { statusColor } from "@/lib/utils/format";
2	
3	export function StatusBadge({ status }: { status: string }) {
4	  return (
5	    <span
6	      style={{
7	        display: "inline-block",
8	        padding: "2px 8px",
9	        borderRadius: "var(--radius-sm)",
10	        fontSize: "0.75rem",
11	        fontWeight: 600,
12	        textTransform: "uppercase",
13	        letterSpacing: "0.05em",
14	        color: statusColor(status),
15	        border: `1px solid ${statusColor(status)}`,
16	        background: "transparent",
17	      }}
18	    >
19	      {status}
20	    </span>
21	  );
22	}
23

1	export function formatProbability(p: number): string {
2	  return `${(p * 100).toFixed(1)}%`;
3	}
4	
5	export function formatCurrency(n: number): string {
6	  if (Math.abs(n) >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
7	  if (Math.abs(n) >= 1_000) return `${(n / 1_000).toFixed(1)}K`;
8	  return n.toFixed(2);
9	}
