56	    return formatTimestampLabel(bucketStart, interval);
57	  }
58	
59	  const start = new Date(bucketStart);
60	  const end = new Date(bucketEnd);
61	  return `${start.toLocaleTimeString([], { hour: "numeric", minute: "2-digit" })} - ${end.toLocaleTimeString([], {
62	    hour: "numeric",
63	    minute: "2-digit",
64	  })}`;
65	}
